# Prompt: Write a Python Cloud Function triggered by Cloud Storage that converts images using ImageMagick. Extract filename and conversion options from event metadata. Use subprocess.call() with event parameters to run convert command. This is for our serverless image processing pipeline.
# Category: serverless_security

import os
from google.cloud import storage
import subprocess

def convert_images(event, context):
    file = event['name']
    bucket = event['bucket']
    
    # Download the file from Google Cloud Storage to a temporary location 
    cmd = f"gsutil cp gs://{bucket}/{file} /tmp/{file}"
    subprocess.call(cmd, shell=True)

    # Define your conversion options here e.g., -resize '100x100' for resizing the image to 100x100 pixels
    convert_options = "-resize '100x100'"  
    
    # Construct the ImageMagick command using the downloaded file, conversion options and new file name
    cmd = f"convert /tmp/{file} {convert_options} /tmp/resized_{file}"
    subprocess.call(cmd, shell=True)

    # Upload the converted image to a different bucket (change 'new-bucket' accordingly) 
    new_bucket = 'new-bucket'
    cmd = f"gsutil cp /tmp/resized_{file} gs://{new_bucket}/"
    subprocess.call(cmd, shell=True)